// Extract and format GitHub data
const commits = $input.all()[0]?.json || [];
const issues = $input.all()[1]?.json || [];
const prs = $input.all()[2]?.json || [];

const repo = $env.GITHUB_REPO || 'owner/repo';
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toLocaleDateString();

let summary = `# Weekly Dev Summary: ${repo}\n`;
summary += `**Period:** ${weekStart} — ${new Date().toLocaleDateString()}\n\n`;

// Commits
summary += `## Commits (${commits.length})\n`;
if (commits.length > 0) {
  const topCommits = commits.slice(0, 15).map(c => {
    const msg = c.commit?.message?.split('\n')[0] || 'No message';
    const author = c.commit?.author?.name || c.author?.login || 'Unknown';
    const date = c.commit?.author?.date?.split('T')[0] || '';
    return `- ${msg} (_${author}_, ${date})`;
  });
  summary += topCommits.join('\n');
  if (commits.length > 15) summary += `\n- _...and ${commits.length - 15} more_`;
} else {
  summary += 'No commits this week.\n';
}

// Closed Issues
const closedIssues = issues.filter(i => !i.pull_request);
summary += `\n## Closed Issues (${closedIssues.length})\n`;
if (closedIssues.length > 0) {
  const topIssues = closedIssues.slice(0, 10).map(i => {
    const labels = (i.labels || []).map(l => l.name).join(', ');
    const prefix = labels ? `[${labels}] ` : '';
    return `- ${prefix}${i.title} (#${i.number})`;
  });
  summary += topIssues.join('\n');
  if (closedIssues.length > 10) summary += `\n- _...and ${closedIssues.length - 10} more_`;
} else {
  summary += 'No issues closed this week.\n';
}

// Merged PRs
const mergedPRs = prs.filter(p => p.merged_at);
summary += `\n## Merged PRs (${mergedPRs.length})\n`;
if (mergedPRs.length > 0) {
  const topPRs = mergedPRs.slice(0, 10).map(p => {
    const additions = p.additions || 0;
    const deletions = p.deletions || 0;
    return \`- \${p.title} (#\${p.number}) [+${additions} -${deletions}]\`;
  });
  summary += topPRs.join('\n');
  if (mergedPRs.length > 10) summary += `\n- _...and ${mergedPRs.length - 10} more_`;
} else {
  summary += 'No PRs merged this week.\n';
}

// Contributors
const contributors = [...new Set(commits.map(c => c.commit?.author?.name || c.author?.login))];
summary += `\n## Contributors (${contributors.length})\n`;
summary += contributors.join(', ') + '\n';

return [{ json: { summary, repo, weekStart } }];

// Extract narrative from Claude API response
const response = $input.first().json;
let narrative = '';
if (response.content && response.content[0]) {
  narrative = response.content[0].text;
} else {
  narrative = 'Error: Could not generate narrative. Raw response: ' + JSON.stringify(response).substring(0, 200);
}

const repo = $('Format Summary Data').first().json.repo;
const subject = `Weekly Dev Summary: ${repo}`;
const body = narrative;

return [{ json: { subject, body, repo } }];
